body.script:
(function(){
  // Speech API check
  var hasSpeech = 'speechSynthesis' in window;
  if(!hasSpeech) document.getElementById('noSpeech').style.display='block';

  var slides = document.querySelectorAll('.slide');
  var total = slides.length;
  var cur = 0;
  var frVoice = null;

  // Preload French voice
  function loadVoice(){
    var voices = speechSynthesis.getVoices();
    for(var i=0;i<voices.length;i++){
      if(voices[i].lang.indexOf('fr')===0){ frVoice=voices[i]; break; }
    }
  }
  if(hasSpeech){
    loadVoice();
    speechSynthesis.onvoiceschanged = loadVoice;
  }

  function render(){
    for(var i=0;i<total;i++){
      slides[i].classList.remove('active','exit-left','exit-right');
      if(i===cur) slides[i].classList.add('active');
      else if(i<cur) slides[i].classList.add('exit-left');
      else slides[i].classList.add('exit-right');
    }
    document.getElementById('prevBtn').style.opacity = cur===0?'.2':'1';
    document.getElementById('nextBtn').style.opacity = cur===total-1?'.2':'1';
    var h = ''+(cur+1)+' / '+total+'';
    for(var i=0;i<total;i++) h += '';
    document.getElementById('footer').innerHTML = h;
  }
  render();

  function go(d){
    var n = cur + d;
    if(n<0 || n>=total) return;
    cur = n;
    render();
  }

  // Navigation buttons
  document.getElementById('prevBtn').addEventListener('click', function(){ go(-1); });
  document.getElementById('nextBtn').addEventListener('click', function(){ go(1); });

  // Keyboard
  document.addEventListener('keydown', function(e){
    if(e.key==='ArrowRight' || e.key==='ArrowDown') go(1);
    if(e.key==='ArrowLeft' || e.key==='ArrowUp') go(-1);
  });

  // Swipe
  var tx=0, ty=0;
  var sw = document.getElementById('sw');
  sw.addEventListener('touchstart', function(e){ tx=e.touches[0].clientX; ty=e.touches[0].clientY; }, {passive:true});
  sw.addEventListener('touchend', function(e){
    var dx = e.changedTouches[0].clientX - tx;
    var dy = e.changedTouches[0].clientY - ty;
    if(Math.abs(dx)>Math.abs(dy) && Math.abs(dx)>40){
      dx<0 ? go(1) : go(-1);
    }
  }, {passive:true});

  // Speak a single phrase
  function say(text, btn){
    if(!hasSpeech) return;
    speechSynthesis.cancel();
    var u = new SpeechSynthesisUtterance(text);
    u.lang = 'fr-FR';
    u.rate = 0.85;
    if(frVoice) u.voice = frVoice;
    if(btn){
      btn.classList.add('playing');
      u.onend = function(){ btn.classList.remove('playing'); };
      u.onerror = function(){ btn.classList.remove('playing'); };
    }
    speechSynthesis.speak(u);
  }

  // Event delegation for all .speak buttons (uses data-text attribute)
  document.addEventListener('click', function(e){
    var btn = e.target.closest('.speak');
    if(btn && btn.dataset.text){
      e.preventDefault();
      say(btn.dataset.text, btn);
      return;
    }
    var playBtn = e.target.closest('.play-all');
    if(playBtn){
      e.preventDefault();
      playAll(playBtn);
    }
  });

  // Play all French text on a slide
  function playAll(btn){
    if(!hasSpeech) return;
    var slide = btn.closest('.slide');
    var texts = [];
    var dataFr = slide.getAttribute('data-fr');
    if(dataFr){
      texts = dataFr.split('|');
    } else {
      var speakBtns = slide.querySelectorAll('.speak[data-text]');
      for(var i=0;i= texts.length) return;
      var u = new SpeechSynthesisUtterance(texts[idx]);
      u.lang = 'fr-FR';
      u.rate = 0.85;
      if(frVoice) u.voice = frVoice;
      u.onend = function(){ idx++; setTimeout(next, 400); };
      u.onerror = function(){ idx++; setTimeout(next, 400); };
      speechSynthesis.speak(u);
    }
    next();
  }

})();
